def Q(c,d,y,eq,eo,ex,hq,ho,hx):
    return {"correctOption":c,"difficulty":d,"sourceYear":y,
            "en":{"question":eq,"options":eo,"explanation":ex},
            "hi":{"question":hq,"options":ho,"explanation":hx}}

def expand(path, qs):
    with open(path,'r',encoding='utf-8') as f: data = json.load(f)
    s = int(data[-1]['id'].split('-')[-1]) if data else 0
    for i,q in enumerate(qs): q['id'] = f"ntpc-ga-{s+i+1:04d}"
    data.extend(qs)
    with open(path,'w',encoding='utf-8') as f: json.dump(data,f,ensure_ascii=False,indent=2)
    print(f"  {os.path.basename(path)}: +{len(qs)} => {len(data)} total")
    return len(qs)

