H1 += [Q("A",M,Y24,"Correct order of Delhi Sultanate dynasties?",["Slave→Khilji→Tughlaq→Sayyid→Lodi","Khilji→Slave→Tughlaq→Lodi→Sayyid","Slave→Tughlaq→Khilji→Lodi→Sayyid","Tughlaq→Slave→Khilji→Sayyid→Lodi"],"Chronological order: Slave/Mamluk (1206-1290), Khilji (1290-1320), Tughlaq (1320-1414), Sayyid (1414-1451), Lodi (1451-1526).","दिल्ली सल्तनत के राजवंशों का सही क्रम?",["गुलाम→खिलजी→तुगलक→सैयद→लोदी","खिलजी→गुलाम→तुगलक→लोदी→सैयद","गुलाम→तुगलक→खिलजी→लोदी→सैयद","तुगलक→गुलाम→खिलजी→सैयद→लोदी"],"कालानुक्रम: गुलाम/ममलूक (1206-1290), खिलजी (1290-1320), तुगलक (1320-1414), सैयद (1414-1451), लोदी (1451-1526)।")]
H1 += [Q("B",M,Y24,"Qutub Minar was completed by which Sultan?",["Qutb-ud-din Aibak","Iltutmish","Alauddin Khilji","Firoz Shah Tughlaq"],"Qutb-ud-din Aibak started Qutub Minar. Iltutmish completed it. Firoz Shah Tughlaq later repaired and added floors after lightning damage.","कुतुब मीनार किस सुल्तान ने पूरा करवाया?",["कुतुब-उद-दीन ऐबक","इल्तुतमिश","अलाउद्दीन खिलजी","फिरोज शाह तुगलक"],"कुतुब-उद-दीन ऐबक ने कुतुब मीनार शुरू करवाया। इल्तुतमिश ने इसे पूरा किया। फिरोज शाह तुगलक ने बाद में बिजली क्षति के बाद मरम्मत कर ऊपरी मंजिलें जोड़ीं।")]
H1 += [Q("C",E,Y24,"First Battle of Panipat: Babur defeated?",["Rana Sanga","Hemu","Ibrahim Lodi","Sher Shah Suri"],"Babur defeated Ibrahim Lodi on April 21, 1526 at Panipat, using superior artillery and Tuluguma tactics.","पानीपत का पहला युद्ध: बाबर ने किसे हराया?",["राणा सांगा","हेमू","इब्राहिम लोदी","शेर शाह सूरी"],"बाबर ने 21 अप्रैल 1526 को पानीपत में श्रेष्ठ तोपखाने और तुलुगुमा रणनीति से इब्राहिम लोदी को हराया।")]
H1 += [Q("A",M,Y24,"Mansabdari system was introduced by?",["Akbar","Babur","Humayun","Shah Jahan"],"Akbar introduced the Mansabdari system around 1570, a military-cum-administrative ranking system with zat (personal rank) and sawar (cavalry maintained).","मनसबदारी प्रणाली किसने शुरू की?",["अकबर","बाबर","हुमायूं","शाहजहां"],"अकबर ने लगभग 1570 में जात (व्यक्तिगत रैंक) और सवार (घुड़सवार सेना) वाली सैन्य-प्रशासनिक मनसबदारी प्रणाली शुरू की।")]
H1 += [Q("B",M,Y24,"Din-i-Ilahi syncretic religion was founded by?",["Jahangir","Akbar","Shah Jahan","Aurangzeb"],"Akbar founded Din-i-Ilahi (Divine Faith) in 1582, combining elements of Hinduism, Islam, Christianity, and Zoroastrianism.","दीन-ए-इलाही की स्थापना किसने की?",["जहांगीर","अकबर","शाहजहां","औरंगज़ेब"],"अकबर ने 1582 में हिंदू धर्म, इस्लाम, ईसाई धर्म और पारसी धर्म के तत्वों को मिलाकर दीन-ए-इलाही (ईश्वरीय धर्म) की स्थापना की।")]
H1 += [Q("D",E,Y24,"Taj Mahal was built in memory of?",["Nur Jahan","Jahanara","Mumtaz Begum","Mumtaz Mahal"],"Shah Jahan built the Taj Mahal at Agra in memory of his beloved wife Mumtaz Mahal. Construction lasted from 1632 to approximately 1653.","ताजमहल किसकी स्मृति में बनवाया गया?",["नूरजहां","जहांआरा","मुमताज बेगम","मुमताज महल"],"शाहजहां ने अपनी प्रिय पत्नी मुमताज महल की स्मृति में आगरा में ताजमहल बनवाया। निर्माण 1632 से लगभग 1653 तक चला।")]
H1 += [Q("C",H,Y24,"Which Mughal emperor was called Zinda Pir (Living Saint)?",["Akbar","Jahangir","Aurangzeb","Shah Jahan"],"Aurangzeb was called Zinda Pir due to his strict adherence to Islamic orthodoxy. He re-imposed Jizya tax and banned music at court.","किस मुगल सम्राट को जिंदा पीर (जीवित संत) कहा जाता था?",["अकबर","जहांगीर","औरंगज़ेब","शाहजहां"],"औरंगज़ेब को उनकी सख्त इस्लामी रूढ़िवादिता के कारण जिंदा पीर कहा जाता था। उन्होंने जजिया कर पुनः लागू किया और दरबार में संगीत पर प्रतिबंध लगाया।")]
H1 += [Q("B",M,Y24,"Fatehpur Sikri was built by which Mughal emperor?",["Humayun","Akbar","Jahangir","Shah Jahan"],"Akbar built Fatehpur Sikri near Agra as his capital (1571-1585). It was later abandoned due to water shortage.","फतेहपुर सीकरी किस मुगल सम्राट ने बनवाया?",["हुमायूं","अकबर","जहांगीर","शाहजहां"],"अकबर ने आगरा के पास फतेहपुर सीकरी को अपनी राजधानी के रूप में बनवाया (1571-1585)। पानी की कमी के कारण बाद में इसे छोड़ दिया गया।")]
H1 += [Q("D",H,Y23,"Second Battle of Panipat (1556) was fought between?",["Babur and Ibrahim Lodi","Humayun and Sher Shah","Akbar and Rana Pratap","Akbar (Bairam Khan) and Hemu"],"Akbar's regent Bairam Khan led the Mughal army to victory over Hemu (Hem Chandra Vikramaditya). Akbar was only 13 years old at the time.","पानीपत का दूसरा युद्ध (1556) किनके बीच लड़ा गया?",["बाबर और इब्राहिम लोदी","हुमायूं और शेरशाह","अकबर और राणा प्रताप","अकबर (बैरम खां) और हेमू"],"अकबर के संरक्षक बैरम खां के नेतृत्व में मुगल सेना ने हेमू (हेम चंद्र विक्रमादित्य) पर विजय प्राप्त की। अकबर उस समय केवल 13 वर्ष के थे।")]
H1 += [Q("A",M,Y24,"Buland Darwaza was built by?",["Akbar","Shah Jahan","Jahangir","Aurangzeb"],"Akbar built the magnificent Buland Darwaza at Fatehpur Sikri in 1601 to commemorate his conquest of Gujarat.","बुलंद दरवाजा किसने बनवाया?",["अकबर","शाहजहां","जहांगीर","औरंगज़ेब"],"अकबर ने गुजरात विजय के उपलक्ष्य में 1601 में फतेहपुर सीकरी में भव्य बुलंद दरवाजा बनवाया।")]
H1 += [Q("C",M,Y24,"Jahangir's autobiography is titled?",["Akbarnama","Humayunnama","Tuzuk-i-Jahangiri","Shahjahannama"],"Tuzuk-i-Jahangiri is the memoirs of Emperor Jahangir, written by himself. Akbarnama was written by Abul Fazl about Akbar.","जहांगीर की आत्मकथा का शीर्षक क्या है?",["अकबरनामा","हुमायूंनामा","तुज़ुक-ए-जहांगीरी","शाहजहांनामा"],"तुज़ुक-ए-जहांगीरी सम्राट जहांगीर के स्वयं द्वारा लिखित संस्मरण हैं। अकबरनामा अबुल फज़ल ने अकबर के बारे में लिखा।")]
H1 += [Q("B",H,Y24,"Nur Jahan's original name was?",["Arjumand Banu Begum","Mehr-un-Nisa","Jodha Bai","Manmati"],"Mehr-un-Nisa was given the title Nur Jahan (Light of the World) by Emperor Jahangir after their marriage in 1611.","नूरजहां का मूल नाम क्या था?",["अर्जुमंद बानू बेगम","मेहर-उन-निसा","जोधा बाई","मनमती"],"मेहर-उन-निसा को सम्राट जहांगीर ने 1611 में विवाह के बाद नूरजहां (दुनिया की रोशनी) की उपाधि दी।")]
H1 += [Q("B",E,Y24,"The Red Fort (Lal Qila) in Delhi was built by?",["Akbar","Shah Jahan","Humayun","Aurangzeb"],"Shah Jahan built the Red Fort between 1639-1648 when he shifted his capital from Agra to Shahjahanabad (present-day Old Delhi).","दिल्ली का लाल किला किसने बनवाया?",["अकबर","शाहजहां","हुमायूं","औरंगज़ेब"],"शाहजहां ने 1639-1648 के बीच अपनी राजधानी आगरा से शाहजहानाबाद (वर्तमान पुरानी दिल्ली) स्थानांतरित करते समय लाल किला बनवाया।")]
H1 += [Q("B",M,Y24,"Shivaji was crowned Chhatrapati in which year?",["1670","1674","1680","1646"],"Shivaji Maharaj was formally crowned as Chhatrapati on June 6, 1674 at Raigad Fort in a grand ceremony presided over by scholar Gaga Bhatt.","शिवाजी का छत्रपति के रूप में राज्याभिषेक कब हुआ?",["1670","1674","1680","1646"],"शिवाजी महाराज का विधिवत राज्याभिषेक 6 जून 1674 को रायगढ़ किले में विद्वान गागा भट्ट की अध्यक्षता में भव्य समारोह में हुआ।")]
H1 += [Q("D",H,Y23,"Third Battle of Panipat (1761) was fought between?",["British and Marathas","Mughals and Marathas","Sikhs and Marathas","Marathas and Ahmad Shah Abdali"],"The Maratha Empire under Sadashivrao Bhau fought against Ahmad Shah Abdali (Durrani). The Marathas suffered a devastating defeat that changed India's power dynamics.","पानीपत का तीसरा युद्ध (1761) किसके बीच हुआ?",["अंग्रेज़ों और मराठों","मुगलों और मराठों","सिखों और मराठों","मराठों और अहमद शाह अब्दाली"],"सदाशिवराव भाऊ के नेतृत्व में मराठा साम्राज्य ने अहमद शाह अब्दाली (दुर्रानी) से युद्ध किया। मराठों की विनाशकारी हार ने भारत की शक्ति गतिशीलता बदल दी।")]
H1 += [Q("C",E,Y24,"The 1857 Revolt began at which location?",["Delhi","Kanpur","Meerut","Lucknow"],"The Revolt of 1857 started on May 10, 1857 at Meerut when sepoys refused to use greased cartridges rumored to contain cow and pig fat.","1857 का विद्रोह कहां से शुरू हुआ?",["दिल्ली","कानपुर","मेरठ","लखनऊ"],"1857 का विद्रोह 10 मई 1857 को मेरठ में शुरू हुआ जब सिपाहियों ने गाय और सूअर की चर्बी युक्त कारतूसों का उपयोग करने से इनकार कर दिया।")]
H1 += [Q("A",M,Y24,"Who led the 1857 revolt at Kanpur?",["Nana Sahib","Tantia Tope","Rani Lakshmibai","Kunwar Singh"],"Nana Sahib (born Dhondu Pant), the adopted son of the last Peshwa Baji Rao II, led the revolt at Kanpur.","कानपुर में 1857 के विद्रोह का नेतृत्व किसने किया?",["नाना साहब","तांत्या टोपे","रानी लक्ष्मीबाई","कुंवर सिंह"],"अंतिम पेशवा बाजीराव द्वितीय के दत्तक पुत्र नाना साहब (जन्म नाम धोंडू पंत) ने कानपुर में विद्रोह का नेतृत्व किया।")]
H1 += [Q("B",E,Y24,"Rani Lakshmibai was associated with which revolt center?",["Kanpur","Jhansi","Delhi","Bareilly"],"Rani Lakshmibai of Jhansi was one of the leading figures of the 1857 revolt. She died fighting British forces at Gwalior on June 17, 1858.","रानी लक्ष्मीबाई किस विद्रोह केंद्र से जुड़ी थीं?",["कानपुर","झांसी","दिल्ली","बरेली"],"झांसी की रानी लक्ष्मीबाई 1857 के विद्रोह की प्रमुख नेत्रियों में से एक थीं। वे 17 जून 1858 को ग्वालियर में ब्रिटिश सेना से लड़ते हुए शहीद हुईं।")]
H1 += [Q("A",M,Y24,"Indian National Congress was founded in which year?",["1885","1890","1900","1882"],"INC was founded on December 28, 1885 at Gokuldas Tejpal Sanskrit College, Bombay. W.C. Bonnerjee was the first president with 72 delegates attending.","भारतीय राष्ट्रीय कांग्रेस की स्थापना कब हुई?",["1885","1890","1900","1882"],"INC की स्थापना 28 दिसंबर 1885 को गोकुलदास तेजपाल संस्कृत कॉलेज, बॉम्बे में हुई। पहले अध्यक्ष डब्ल्यू.सी. बनर्जी थे और 72 प्रतिनिधि उपस्थित थे।")]
H1 += [Q("D",H,Y23,"Who presided over the 1929 Lahore INC session declaring Purna Swaraj?",["Mahatma Gandhi","Motilal Nehru","Subhas Chandra Bose","Jawaharlal Nehru"],"Jawaharlal Nehru presided over the Lahore session in December 1929 where the historic Purna Swaraj (complete independence) resolution was passed. January 26, 1930 was celebrated as the first Independence Day.","1929 के लाहौर INC अधिवेशन की अध्यक्षता किसने की?",["महात्मा गांधी","मोतीलाल नेहरू","सुभाष चंद्र बोस","जवाहरलाल नेहरू"],"जवाहरलाल नेहरू ने दिसंबर 1929 में लाहौर अधिवेशन की अध्यक्षता की जहां ऐतिहासिक पूर्ण स्वराज प्रस्ताव पारित हुआ। 26 जनवरी 1930 को पहला स्वतंत्रता दिवस मनाया गया।")]
H1 += [Q("C",E,Y24,"The slogan 'Do or Die' was given by?",["Subhas Chandra Bose","Jawaharlal Nehru","Mahatma Gandhi","Sardar Patel"],"Mahatma Gandhi gave the 'Do or Die' (Karo ya Maro) call on August 8, 1942 at the Bombay AICC session, launching the Quit India Movement.","'करो या मरो' का नारा किसने दिया?",["सुभाष चंद्र बोस","जवाहरलाल नेहरू","महात्मा गांधी","सरदार पटेल"],"महात्मा गांधी ने 8 अगस्त 1942 को बॉम्बे AICC अधिवेशन में 'करो या मरो' का आह्वान किया और भारत छोड़ो आंदोलन शुरू किया।")]
H1 += [Q("B",M,Y24,"The Dandi March began on which date?",["March 12, 1931","March 12, 1930","April 6, 1930","April 12, 1930"],"The Salt March started from Sabarmati Ashram on March 12, 1930. Gandhi and 78 followers reached Dandi on April 6, covering 241 miles, and broke the salt law.","दांडी मार्च (नमक सत्याग्रह) कब शुरू हुआ?",["12 मार्च 1931","12 मार्च 1930","6 अप्रैल 1930","12 अप्रैल 1930"],"नमक मार्च 12 मार्च 1930 को साबरमती आश्रम से शुरू हुआ। गांधी और 78 अनुयायी 241 मील चलकर 6 अप्रैल को दांडी पहुंचे और नमक कानून तोड़ा।")]
H1 += [Q("C",M,Y24,"The Cabinet Mission (1946) had how many members?",["2","3","4","5"],"The Cabinet Mission consisted of 3 British Cabinet ministers: Sir Stafford Cripps, Lord Pethick-Lawrence, and A.V. Alexander.","कैबिनेट मिशन (1946) में कितने सदस्य थे?",["2","3","4","5"],"कैबिनेट मिशन में 3 ब्रिटिश कैबिनेट मंत्री थे: सर स्टैफोर्ड क्रिप्स, लॉर्ड पेथिक-लॉरेंस और ए.वी. अलेक्जेंडर।")]
H1 += [Q("B",E,Y24,"British PM when India gained independence?",["Winston Churchill","Clement Attlee","Neville Chamberlain","Harold Macmillan"],"Clement Attlee of the Labour Party was the British PM. He sent the Cabinet Mission and appointed Lord Mountbatten as the last Viceroy.","भारत की स्वतंत्रता के समय ब्रिटिश प्रधानमंत्री कौन थे?",["विंस्टन चर्चिल","क्लेमेंट एटली","नेविल चैंबरलेन","हेरोल्ड मैकमिलन"],"लेबर पार्टी के क्लेमेंट एटली ब्रिटिश प्रधानमंत्री थे। उन्होंने कैबिनेट मिशन भेजा और लॉर्ड माउंटबेटन को अंतिम वायसराय नियुक्त किया।")]
H1 += [Q("C",M,Y24,"Who drew the Radcliffe Line?",["Lord Mountbatten","Stafford Cripps","Cyril Radcliffe","A.V. Alexander"],"Sir Cyril Radcliffe chaired the Boundary Commission that drew the Radcliffe Line on August 17, 1947, partitioning Punjab and Bengal between India and Pakistan.","रैडक्लिफ रेखा किसने खींची?",["लॉर्ड माउंटबेटन","स्टैफोर्ड क्रिप्स","सिरिल रैडक्लिफ","ए.वी. अलेक्जेंडर"],"सर सिरिल रैडक्लिफ ने सीमा आयोग की अध्यक्षता की और 17 अगस्त 1947 को भारत-पाकिस्तान के बीच पंजाब और बंगाल का विभाजन करती रैडक्लिफ रेखा खींची।")]
